      ExecuteProcess('IMF.P.Log.Event', 'pPrefix', sPrefix, 'pSeverity', 'WARNING', 'pObjectType', 'PROCESS', 'pObjectName', sBedrockProcess, 'pMessage', 'Bedrock relation copy failed. IMF fallback remains TODO until hierarchy traversal is implemented.', 'pRunId', sSourceDimension | '->' | sTargetDimension);
